import{_ as o,o as e,c as s,a2 as n}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"06 · Coding Plan：订阅套餐与计费","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/06-coding-plan.md","filePath":"claude-code/06-coding-plan.md"}'),a={name:"claude-code/06-coding-plan.md"};function d(r,t,c,g,l,p){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="_06-·-coding-plan-订阅套餐与计费" tabindex="-1">06 · Coding Plan：订阅套餐与计费 <a class="header-anchor" href="#_06-·-coding-plan-订阅套餐与计费" aria-label="Permalink to &quot;06 · Coding Plan：订阅套餐与计费&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./05-third-party-models">05 接入第三方 / 国产模型</a> 教你把 DeepSeek、Kimi、GLM 接进 Claude Code。这一篇把账算清楚——<strong>到底该订哪个套餐、钱怎么花的、怎么查用量、怎么省</strong>。</p></blockquote><p>官方文档里有个数字第一眼看到容易愣一下：企业部署里，<strong>每个开发者平均每个活跃日烧掉约 13 美元、每月 150–250 美元</strong>（来源：官方 <a href="https://code.claude.com/docs/zh-CN/costs" target="_blank" rel="noreferrer">costs</a> 文档）。13 美元一天，按汇率就是九十多块，一个月小两千——这还只是「平均」。</p><p>我自己刚用 Claude Code 接官方 API（按量计费）那会儿就吃过亏：没装任何用量提示，闷头干了一周。周末打开 Console 一看账单 <strong>$40 出头</strong>——钱不算多，但我完全说不清是怎么花出去的：哪次对话烧得多？模型选错了还是上下文堆太满？一笔糊涂账。</p><p>这一篇就来把账算明白。<strong>搞清楚计费逻辑，比盲目找便宜套餐重要得多</strong>——同一个套餐，会用的人撑一个月，不会用的人三天触顶。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一张「按量计费 vs 订阅套餐 vs 国产 Coding Plan」的对比表，知道自己该选哪条路</li><li>看懂 Claude Code 的计费单位（token），知道钱到底花在哪</li><li>几个命令（<code>/usage</code> 查用量、<code>/usage-credits</code> 设上限、<code>/status</code> 核配置），自己就能盯住开销</li><li>一套实测有效的省钱习惯，<strong>同样的活儿，token 能少烧一大截</strong></li></ul><hr><h2 id="_01-先搞清楚-你在为什么付费" tabindex="-1">01 先搞清楚：你在为什么付费 <a class="header-anchor" href="#_01-先搞清楚-你在为什么付费" aria-label="Permalink to &quot;01 先搞清楚：你在为什么付费&quot;">​</a></h2><p>先说结论：<strong>Claude Code 本身免费，你付的是「模型算力」的钱</strong>。</p><p>Claude Code 只是个跑在终端里的命令行工具，下载不要钱。真正花钱的是它背后的大模型——你提问、它读文件、它写代码，都要把内容发给模型处理，<strong>这个处理量就是计费单位</strong>。</p><p><strong>类比：Claude Code 是出租车，模型是里程。</strong> 上车免费、车也免费给你坐，但一开起来<strong>跑的每一公里都在跳表</strong>——你问得越多、让它读的文件越大、它想得越久，「里程」就越长。</p><p>这个「里程」的计量单位叫 <strong>token</strong>。<strong>类比：token 就是文字的「计价字数」。</strong> 模型把文字切成一小块一小块来数——按 Anthropic 官方<a href="https://platform.claude.com/docs/zh-CN/about-claude/glossary" target="_blank" rel="noreferrer">平台术语表</a>，<strong>对于 Claude，1 个 token 大约代表 3.5 个英文字符，确切数字因语言而异</strong>（中文未给固定比例）；你发出去的算「输入 token」、它回来的算「输出 token」，分别计价、输出通常更贵。</p><p>举几个你天天遇到的场景，感受下 token 怎么堆起来：</p><ul><li>让它「读一下这个 2000 行的文件再改」——<strong>整个文件都变成输入 token 发出去了</strong></li><li>一轮对话聊到第 50 条——<strong>前面 49 条作为上下文每次都重发一遍</strong>（这是大头，第 05 节的 <code>/clear</code> 习惯就是针对这个）</li><li>开了扩展思考（extended thinking），它「想」一大段才动手——<strong>思考过程算输出 token</strong></li></ul><p>所以<strong>花钱多少跟「问了几个问题」关系不大，跟「每次塞多少上下文」关系极大</strong>——这是后面省钱的核心抓手。</p><blockquote><p>💡 一句话总结：工具免费，<strong>你付的是模型按 token 计的算力费</strong>——输入 + 输出 + 思考，全都算钱。</p></blockquote><hr><h2 id="_02-三条路怎么选-按量计费-官方订阅-国产-coding-plan" tabindex="-1">02 三条路怎么选：按量计费 / 官方订阅 / 国产 Coding Plan <a class="header-anchor" href="#_02-三条路怎么选-按量计费-官方订阅-国产-coding-plan" aria-label="Permalink to &quot;02 三条路怎么选：按量计费 / 官方订阅 / 国产 Coding Plan&quot;">​</a></h2><p>知道了为 token 付费，下个问题是：<strong>这钱通过什么渠道付？</strong> 主流就三条路，先上表再说人话。</p><table tabindex="0"><thead><tr><th>方案</th><th>怎么收费</th><th>月成本（参考）</th><th>适合谁</th><th>主要坑</th></tr></thead><tbody><tr><td><strong>官方按量计费</strong>（API / Console）</td><td>按 token 用量、用多少扣多少</td><td>浮动，重度用户 $150–250+</td><td>想用官方原生模型、用量稳定</td><td>账单浮动、可能超预算；需绑卡（美元）</td></tr><tr><td><strong>官方订阅</strong>（Pro / Max / Team）</td><td>固定月费、包含一定额度</td><td>固定（以官方 pricing 为准）</td><td>高频用、想要固定支出、用官方模型</td><td>海外支付、需魔法上网；额度有上限</td></tr><tr><td><strong>国产 Coding Plan</strong>（方舟 / 百炼 / 讯飞等）</td><td>固定月费、多工具共享额度</td><td>低，<strong>首月常有促销</strong></td><td>国内用户、对成本敏感、能接受国产模型</td><td>模型非 Claude；额度按厂商规则；价格多变</td></tr></tbody></table><p><strong>这三条路不是「哪个最好」，是「你是谁」。</strong> 表格之外补两点：</p><p><strong>官方两条路</strong>——按量计费用原生 Claude 模型（编程第一梯队）、最灵活但账单浮动（前面那笔糊涂的 $40 就是它）；订阅心理负担最小、Max 适合重度用户，但<strong>需要海外支付 + 魔法上网</strong>，几档多少钱<strong>一律以官方 <a href="https://claude.com/pricing" target="_blank" rel="noreferrer">claude.com/pricing</a> 为准</strong>，这里不写死。</p><p><strong>国产 Coding Plan</strong> 是国内开发者现在最实际的选择。火山方舟、阿里百炼、讯飞星辰都推出了「Coding Plan」——<strong>专为 AI 编程工具设计的订阅服务，固定月费、远低于按量计费、兼容 Claude Code</strong>，把千问、Kimi、GLM、DeepSeek、豆包、MiniMax 整合进来，多工具（Cursor、Cline 等）<strong>共享一份额度</strong>。</p><blockquote><p>⚠️ <strong>国产 Coding Plan 的价格促销极其频繁</strong>，网传「首月 9.9 / 49.9」之类是某时段活动价，<strong>随时会变、活动会下架</strong>。本文不引用具体金额，请直接到厂商活动页看当前价。</p></blockquote><p>接入方式（Base URL、ANTHROPIC_MODEL）上一篇已讲透，不重复。但有<strong>一个计费大坑必须单独拎出来</strong>，下一节专门说。</p><blockquote><p>💡 一句话总结：<strong>官方原生选订阅或按量，国内省钱选 Coding Plan</strong>——先想清楚自己是谁，再挑路，别只看价格。</p></blockquote><hr><h2 id="_03-国产-coding-plan-的计费坑-base-url-选错-钱白花" tabindex="-1">03 国产 Coding Plan 的计费坑：Base URL 选错，钱白花 <a class="header-anchor" href="#_03-国产-coding-plan-的计费坑-base-url-选错-钱白花" aria-label="Permalink to &quot;03 国产 Coding Plan 的计费坑：Base URL 选错，钱白花&quot;">​</a></h2><p>单独拎出来，因为<strong>太多人栽在这</strong>——明明买了 Coding Plan，月底却收到一笔额外账单。根源是：<strong>同一个厂商往往有两套 Base URL，一套走套餐额度、一套走按量计费，长得还很像</strong>。以火山方舟为例：</p><table tabindex="0"><thead><tr><th>Base URL</th><th>走哪笔钱</th><th>用途</th></tr></thead><tbody><tr><td><code>https://ark.cn-beijing.volces.com/api/coding</code></td><td>✅ <strong>消耗 Coding Plan 套餐额度</strong></td><td>接 Claude Code 该用这个</td></tr><tr><td><code>https://ark.cn-beijing.volces.com/api/v3</code></td><td>❌ <strong>不走套餐，单独按量扣费</strong></td><td>普通 API 调用</td></tr></tbody></table><p>看出来了吗？<strong>就差 <code>coding</code> 和 <code>v3</code> 一个词</strong>。你买了套餐、本以为固定月费封顶，结果配置时手一抖填成 <code>/api/v3</code>，套餐额度一点没动，<strong>所有调用全走了按量计费、月底额外掏钱</strong>。阿里百炼也类似——它的 <strong>Coding Plan 专属 Key（<code>sk-sp-</code> 开头）和按量计费普通 Key（<code>sk-</code> 开头）不互通</strong>，混用同样出问题。</p><p>所以接国产 Coding Plan，记住两条铁律：<strong>Base URL 必须带 <code>coding</code> 字样</strong>；<strong>API Key 用套餐专属的那把</strong>，别拿按量计费的 Key 顶上。上面方舟、百炼的具体地址和 Key 前缀都是<strong>第三方厂商的私有规则，会随厂商调整而变</strong>，动手前请以各厂商官方文档 / 控制台的当前说明为准。</p><p>配火山方舟时一旦填错成 v3，要是当晚习惯性跑了下 <code>/usage</code> 看用量，就会发现「套餐额度怎么没动、Console 按量这边反而有数」，赶紧改回 coding。<strong>这种坑靠肉眼查配置很难发现，靠盯用量才抓得出来。</strong></p><blockquote><p>💡 一句话总结：买了套餐 ≠ 走套餐——<strong>Base URL 选带 <code>coding</code> 的、Key 用套餐专属的</strong>，配完立刻核对，否则钱悄悄从另一个口子流走。</p></blockquote><hr><h2 id="_04-怎么查用量-三个命令盯住你的钱包" tabindex="-1">04 怎么查用量：三个命令盯住你的钱包 <a class="header-anchor" href="#_04-怎么查用量-三个命令盯住你的钱包" aria-label="Permalink to &quot;04 怎么查用量：三个命令盯住你的钱包&quot;">​</a></h2><p>光交钱不看用量，等于蒙眼开车。Claude Code 内置了几个命令<strong>让你随时知道钱花在哪</strong>，逐个说。</p><h3 id="usage-最全的用量面板-用得最勤的一个" tabindex="-1"><code>/usage</code>：最全的用量面板（用得最勤的一个） <a class="header-anchor" href="#usage-最全的用量面板-用得最勤的一个" aria-label="Permalink to &quot;\`/usage\`：最全的用量面板（用得最勤的一个）&quot;">​</a></h3><p>在对话框直接敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/usage</span></span></code></pre></div><p>它顶部的 <strong>Session 块</strong>显示当前会话的详细 token 用量，长这样（来源：官方 costs 文档）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total cost:            $0.55</span></span>
<span class="line"><span>Total duration (API):  6m 19.7s</span></span>
<span class="line"><span>Total duration (wall): 6h 33m 10.2s</span></span>
<span class="line"><span>Total code changes:    0 lines added, 0 lines removed</span></span></code></pre></div><p>四行是：估算总花销、API 实际处理时长、挂窗口的真实时长、代码改动行数。<strong>干完一个任务就随手敲一下，对当次开销有个数。</strong> 但官方有个重要提醒：</p><blockquote><p>Session 块里的美元数字是<strong>从 token 数本地估算的</strong>，可能和实际账单不同。<strong>权威计费看 <a href="https://platform.claude.com/usage" target="_blank" rel="noreferrer">Claude Console</a> 的使用页面。</strong>（来源：官方 costs 文档）</p></blockquote><p>如果你用<strong>官方 Pro / Max / Team / Enterprise 订阅</strong>，<code>/usage</code> 还会多一块<strong>额度用量明细</strong>——把最近消耗按 skills、subagents、plugins、各 MCP server 拆开显示占比，按 <code>d</code> / <code>w</code> 切换「过去 24 小时 / 7 天」。注意这是<strong>从本机会话历史算出的近似值</strong>，不含其他设备或 claude.ai 的用量。（来源：官方 costs 文档）</p><h3 id="usage-credits-给自己设个月度上限-防超支神器" tabindex="-1"><code>/usage-credits</code>：给自己设个月度上限（防超支神器） <a class="header-anchor" href="#usage-credits-给自己设个月度上限-防超支神器" aria-label="Permalink to &quot;\`/usage-credits\`：给自己设个月度上限（防超支神器）&quot;">​</a></h3><p>这个是<strong>官方 Pro / Max 计划专属</strong>功能（来源：官方 costs 文档）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/usage-credits</span></span></code></pre></div><p>它能让你在使用额度上<strong>设一个每月支出上限</strong>。一旦花到这个数，Claude Code 会提示你「提高上限还是移除限制」，直接在 CLI 里决定。改这个限制需要账户的<strong>计费访问权限</strong>（billing access）。</p><p><strong>新手强烈建议一上来就用它设个上限</strong>——比如预算 100 块一个月，触顶就拦你，比月底看账单吓一跳强太多。我那笔糊涂的 $40，恰恰就是因为当时压根不知道有这命令。</p><p>还有个 <code>/status</code>，打开设置界面的 Status 标签，按官方 commands 文档显示 <strong>version、model、account、connectivity</strong>（版本、模型、账户、连通性）。官方在<a href="https://code.claude.com/docs/zh-CN/third-party-integrations" target="_blank" rel="noreferrer">第三方集成文档</a>里建议「用 <code>/status</code> 验证你的代理和网关配置是否正确应用」——<strong>它正是上一节核对接入配置的工具</strong>，配完套餐敲一下、确认模型和连通性正常再干活。</p><table tabindex="0"><thead><tr><th>命令</th><th>适用场景</th><th>注意事项</th></tr></thead><tbody><tr><td><code>/usage</code></td><td>查当前会话 token 用量与估算花销</td><td>金额是本地估算，权威账单看 Console</td></tr><tr><td><code>/usage-credits</code></td><td>设月度使用上限、防超支</td><td>仅官方 Pro / Max 计划可用</td></tr><tr><td><code>/status</code></td><td>核对 version、model、account、连通性</td><td>验证接入配置是否生效的第一步</td></tr></tbody></table><blockquote><p>💡 一句话总结：<code>/usage</code> 看明细、<code>/usage-credits</code> 设上限、<code>/status</code> 核配置——<strong>三个命令把钱包焊死</strong>。</p></blockquote><hr><h2 id="_05-省钱的真功夫-让同样的活儿少烧-token" tabindex="-1">05 省钱的真功夫：让同样的活儿少烧 token <a class="header-anchor" href="#_05-省钱的真功夫-让同样的活儿少烧-token" aria-label="Permalink to &quot;05 省钱的真功夫：让同样的活儿少烧 token&quot;">​</a></h2><p>换便宜套餐是下策，<strong>会用工具才是上策</strong>。回到 01 节那句——<strong>花钱多少跟你塞进去多少上下文极度相关</strong>，所以省钱核心就一句：<strong>别让模型读没用的、想没必要的弯路</strong>。下面都来自官方 costs 文档，挑的是对新手最立竿见影的几条。</p><p><strong>第一，任务之间用 <code>/clear</code> 清空。</strong> 这是<strong>回报最高的习惯</strong>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/clear</span></span></code></pre></div><p>我自己以前就是一个窗口从早开到晚，上午修 bug、下午写新功能全挤在一个会话里，图省事懒得切。问题是<strong>上下文累积</strong>：下午每个问题都把上午那堆早没用的对话重发一遍，token 白白翻倍——后来盯 <code>/usage</code> 才发现下午那几条对话单价明显比上午高，就是这么烧出来的。官方原话：</p><blockquote><p>使用 <code>/clear</code> 在切换到不相关的工作时重新开始。陈旧的上下文会在随后的每条消息上浪费令牌。</p></blockquote><p>养成习惯：<strong>一个独立任务做完立刻 <code>/clear</code></strong>，切到不相关的活儿绝不在旧会话里硬接。就这一下，长会话开销砍掉一大块。</p><p><strong>第二，选对模型，别拿大炮打蚊子。</strong> 官方原则是「Sonnet 处理大多数编程任务都很好、成本低于 Opus，把 Opus 留给复杂架构和多步推理」（来源：costs 文档）。说人话：<strong>日常改代码、写函数、调小 bug，Sonnet 完全够</strong>；只有「重构整个模块」这种硬骨头才用 <code>/model</code> 切 Opus。更简单的 subagent 任务甚至可以在 subagent 配置里指定 Haiku，单价更低。默认挂 Sonnet，<strong>一周也就切两三次</strong>。</p><p><strong>第三，复杂任务先用 plan mode（规划模式）。</strong> 按 <code>Shift+Tab</code> 进入，让它先探索代码库、提方案给你批准再动手——<strong>方向错了的返工最烧钱</strong>。这坑很常见：让它改一个没说清的需求，它埋头改了七八个文件、方向全错，这段 token 全打水漂。</p><p><strong>第四，提示写具体点。</strong> 你越含糊，它越要满世界翻文件猜你想干嘛，每翻一个都是 token。官方原话对比：「改进此代码库」触发广泛扫描，「给 auth.ts 的登录函数加输入校验」让它以最少文件读取高效工作。</p><p>下面这张表可以当成贴在显示器边上的「省钱速查」：</p><table tabindex="0"><thead><tr><th>坏习惯 ❌</th><th>好习惯 ✅</th><th>省在哪</th></tr></thead><tbody><tr><td>一个会话从早用到晚</td><td>任务间 <code>/clear</code></td><td>不重发陈旧上下文</td></tr><tr><td>全程挂 Opus</td><td>默认 Sonnet，难题才切 Opus</td><td>单价更低</td></tr><tr><td>含糊需求直接开干</td><td>复杂任务先 plan mode</td><td>少返工、少瞎扫</td></tr><tr><td>「帮我改进下代码」</td><td>「给 auth.ts 的登录函数加输入校验」</td><td>少读无关文件</td></tr></tbody></table><p>冷知识（来源：官方 costs 文档）：<strong>Claude Code 空闲时也会用一点点 token</strong>——比如为 <code>claude --resume</code> 后台总结旧对话。但量很小，<strong>通常每个会话不到 $0.04</strong>，不用担心。</p><blockquote><p>💡 一句话总结：省钱不是换便宜套餐，是 <strong><code>/clear</code> 勤清、Sonnet 兜底、复杂先 plan、提示说清</strong>——上下文越小，账单越薄。</p></blockquote><hr><h2 id="_06-动手-三步盯住你这周的开销" tabindex="-1">06 动手：三步盯住你这周的开销 <a class="header-anchor" href="#_06-动手-三步盯住你这周的开销" aria-label="Permalink to &quot;06 动手：三步盯住你这周的开销&quot;">​</a></h2><p>光看不练等于没看。下面这套动作<strong>你现在就能跑一遍</strong>，五分钟建立起「用量感知」。</p><p><strong>前提</strong>：已按前几篇装好并配好 Claude Code（官方订阅或国产 Coding Plan 都行）。在项目目录下启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path/to/your_project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>第一步：核对配置没填错口子。</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/status</span></span></code></pre></div><p>它会打开设置界面的 Status 标签，按官方 commands 文档显示 <strong>version、model、account、connectivity</strong>（版本、模型、账户、连通性）——重点确认<strong>模型是你想用的那个、连通性正常</strong>，否则说明接入没配对。</p><p>Base URL 本身不在 <code>/status</code> 的输出里，得回去核对你写的环境变量：国产 Coding Plan 用户<strong>确认 <code>ANTHROPIC_BASE_URL</code> 带 <code>coding</code> 字样</strong>（如 <code>.../api/coding</code>），不是 <code>/api/v3</code> 之类的按量地址。填错了回 05 篇那套环境变量里改对、重开终端再启动。</p><p><strong>第二步：随便问个问题，看花了多少。</strong> 先让它干点小活：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我看看当前目录下有哪些文件，简单说下这个项目是干嘛的</span></span></code></pre></div><p>等它回完，敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/usage</span></span></code></pre></div><p>顶部 Session 块预期长这样：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total cost:            $0.0X</span></span>
<span class="line"><span>Total duration (API):  Xs</span></span>
<span class="line"><span>Total duration (wall): Xs</span></span>
<span class="line"><span>Total code changes:    0 lines added, 0 lines removed</span></span></code></pre></div><p>记住这个数。<strong>这就是「问一个简单问题 + 读一遍目录」的成本</strong>——有了基准，以后哪次对话异常烧钱你一眼能察觉。</p><p><strong>第三步：设月度上限（官方 Pro / Max 用户）。</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/usage-credits</span></span></code></pre></div><p>按提示设一个你能接受的上限。设完触顶它会主动拦你、问要不要提高，<strong>等于给钱包上了保险栓</strong>。</p><blockquote><p>国产 Coding Plan 用户：<code>/usage-credits</code> 针对官方使用额度，不一定适用于你的厂商套餐——额度和用量<strong>以厂商控制台为准</strong>，但 <code>/usage</code>、<code>/clear</code> 这些习惯照样要养成。</p></blockquote><p>跑完这三步，你就从「闷头烧钱」升级成「随时知道烧了多少、还能设闸」。</p><blockquote><p>💡 一句话总结：<strong><code>/status</code> 核口子 → <code>/usage</code> 建基准 → <code>/usage-credits</code> 设上限</strong>，五分钟拿回开销掌控权。</p></blockquote><hr><h2 id="_07-小结" tabindex="-1">07 小结 <a class="header-anchor" href="#_07-小结" aria-label="Permalink to &quot;07 小结&quot;">​</a></h2><p>这一篇把 Claude Code 的「钱」掰开揉碎讲了一遍。</p><table tabindex="0"><thead><tr><th>你学到的</th><th>关键点</th></tr></thead><tbody><tr><td><strong>为什么付费</strong></td><td>工具免费，付的是模型按 token 计的算力费</td></tr><tr><td><strong>三条路怎么选</strong></td><td>官方原生→订阅/按量；国内省钱→Coding Plan</td></tr><tr><td><strong>国产套餐的坑</strong></td><td>Base URL 选带 <code>coding</code> 的、Key 用专属的</td></tr><tr><td><strong>怎么查用量</strong></td><td><code>/usage</code> 看明细、<code>/usage-credits</code> 设上限、<code>/status</code> 核配置</td></tr><tr><td><strong>怎么省钱</strong></td><td><code>/clear</code> 勤清、Sonnet 兜底、复杂先 plan、提示说清</td></tr></tbody></table><p>只记一条的话：<strong>花钱多少跟「塞进去多少上下文」极度相关，不是跟「问了几个问题」</strong>。吃透这句，省钱的招数你都能自己推导出来——<strong>看懂账单逻辑、查清当次开销、设月度上限、把活儿干得更省</strong>，到这你都拿下了。</p><p>⚠️ 再强调一次准确性：本文涉及的<strong>套餐价格、促销、额度规则都会变动</strong>，金额一律以官方 <a href="https://claude.com/pricing" target="_blank" rel="noreferrer">claude.com/pricing</a> 或国产厂商活动页为准；<code>/usage-credits</code> 等命令行为以<a href="https://code.claude.com/docs/zh-CN/costs" target="_blank" rel="noreferrer">官方 costs 文档</a>为准，可能随版本更新（<code>claude --version</code> 看版本）。</p><hr><p>账算明白了，套餐也选好了，下一篇 <strong>07「第一次使用：跑通第一个例子」</strong>——正式启动 Claude Code，从一个最小的真实项目开始，把「想 → 做 → 看」的代理循环亲手跑一遍。<strong>铺垫够多了，是时候动真格了。</strong></p>`,99)])])}const u=o(a,[["render",d]]);export{h as __pageData,u as default};
